// n8n RSS node returns one item per feed entry. After merge we have all entries.
// item.json fields: title, link, pubDate, content, contentSnippet, creator, isoDate

// Keywords that indicate observability / failure pattern relevance
const OBS_KEYWORDS = [
  'opentelemetry', 'otel', 'prometheus', 'grafana loki', 'jaeger', 'tempo',
  'collector', 'metric', 'distributed trace', 'span', 'observability',
  'alert', 'incident', 'outage', 'latency', 'error rate', 'saturation',
  'kubernetes', 'k8s', 'cardinality', 'scrape', 'exporter', 'instrumentation',
  'backpressure', 'telemetry drop', 'memory leak', 'cpu throttl', 'oom'
];

// Keywords that disqualify (marketing / noise)
const SKIP_PHRASES = [
  'webinar', 'virtual event', 'conference', 'sponsorship',
  'case study: small business', 'partner spotlight'
];

// Only look at articles published within the last 30 days
const CUTOFF_MS = Date.now() - (30 * 24 * 60 * 60 * 1000);

const seenUrls = new Set();
const output   = [];

for (const item of items) {
  const entry = item.json;
  if (!entry || !entry.link) continue;

  // Dedup by URL
  if (seenUrls.has(entry.link)) continue;
  seenUrls.add(entry.link);

  // Age gate
  const pubDate = entry.isoDate ? new Date(entry.isoDate).getTime() : 0;
  if (pubDate > 0 && pubDate < CUTOFF_MS) continue;

  // Relevance check
  const titleLower   = (entry.title   || '').toLowerCase();
  const contentLower = (entry.contentSnippet || entry.content || '').toLowerCase();
  const fullText     = titleLower + ' ' + contentLower;

  const isRelevant = OBS_KEYWORDS.some(kw => fullText.includes(kw));
  if (!isRelevant) continue;

  const isNoise = SKIP_PHRASES.some(p => fullText.includes(p));
  if (isNoise) continue;

  // Derive source label from URL domain
  let source = 'blog';
  try {
    const domain = new URL(entry.link).hostname.replace('www.', '').split('.')[0];
    source = `blog-${domain}`;
  } catch(e) {}

  // Use link as source_id (URL is unique enough)
  const sourceId = `${source}-${Buffer.from(entry.link).toString('base64').substring(0, 32)}`;

  output.push({
    json: {
      source:    source,
      source_id: sourceId,
      url:       entry.link,
      title:     entry.title || '',
      body:     (entry.contentSnippet || entry.content || '').replace(/<[^>]+>/g, '').substring(0, 4000),
      author:    entry.creator || 'unknown',
      score:     1,   // blogs don't have engagement scores; treat all as score=1
      tags:      ['blog', 'observability']
    }
  });
}

if (output.length === 0) {
  return [{ json: { _skip: true, reason: 'no relevant blog posts found' } }];
}

return output;
